package com.aadil.jobtracker.security;import com.aadil.jobtracker.UserRepository.UserRepository;import com.aadil.jobtracker.entity.UserEntity;import org.springframework.security.authentication.AuthenticationManager;import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;import org.springframework.security.core.Authentication;import org.springframework.security.core.userdetails.User;import org.springframework.security.core.userdetails.UserDetails;import org.springframework.security.core.userdetails.UsernameNotFoundException;import org.springframework.security.crypto.password.PasswordEncoder;import org.springframework.stereotype.Service;import java.util.ArrayList;@Servicepublic class AuthenticationService {    private final UserRepository userRepository;    private final PasswordEncoder passwordEncoder;    private final AuthenticationManager authenticationManager;    private final JwtUtility jwtUtility;    public AuthenticationService(UserRepository userRepository, PasswordEncoder passwordEncoder, AuthenticationManager authenticationManager, JwtUtility jwtUtility) {        this.userRepository = userRepository;        this.passwordEncoder = passwordEncoder;        this.authenticationManager = authenticationManager;        this.jwtUtility = jwtUtility;    }    public String register (RequestRegisterDTO register){        if (userRepository.findByEmail(register.getEmail()).isPresent()){            throw new RuntimeException("User email is already exists");        }        if (register.getPassword()==null || register.getPassword().isBlank() || register.getPassword().length()>6){            throw new RuntimeException("Password is required and should be below 6 Characters");        }        if (register.getEmail()==null || register.getEmail().isBlank()){            throw new RuntimeException("Email is Required");        }        String hashedPassword = passwordEncoder.encode(register.getPassword());        UserEntity user = new UserEntity();        user.setName(register.getUsername());        user.setEmail(register.getEmail());        user.setPassword(hashedPassword);        user.setRoles(UserRoles.USER.getUserRoles());        userRepository.save(user);        return "User registered Successfully";    }    public String login (String email, String password){        userRepository.findByEmail(email).orElseThrow(()->new UsernameNotFoundException("Email NOT found"));        Authentication authentication = authenticationManager.authenticate(new UsernamePasswordAuthenticationToken(email,password));        if (authentication.isAuthenticated()){            UserDetails userDetails = new User(email,"",new ArrayList<>());            jwtUtility.generateToken(userDetails);        }        throw new RuntimeException("Invalid Credentials");    }}